169	
170	function ProfilePictureCard({
171	  photoFileId,
172	  firstName,
173	}: {
174	  photoFileId: string | null;
175	  firstName: string;
176	}) {
177	  const fileInputRef = useRef<HTMLInputElement>(null);
178	  const { mutate: updatePhoto, isPending: isUpdating } =
179	    useUpdateProfilePhoto();
180	  const { mutate: uploadFile, isPending: isUploading } = useFileUpload();
181	  const { data: photoData } = useSignedFileUrl(
182	    photoFileId ?? "",
183	    !!photoFileId
184	  );
185	
186	  const isPending = isUploading || isUpdating;
187	
188	  function handleReplaceClick() {
189	    fileInputRef.current?.click();
190	  }
191	
192	  function handleFileChange(event: React.ChangeEvent<HTMLInputElement>) {
193	    const file = event.target.files?.[0];
194	    if (!file) return;
195	
196	    uploadFile(
197	      {
198	        file,
199	        folder: S3_FOLDERS.STATIC,
200	        mime: file.type as MimeType,
201	        fileName: file.name,
202	      },
203	      {
204	        onSuccess: (uploaded) => {
205	          updatePhoto(
206	            { photoFileId: uploaded.fileId },
207	            {
208	              onSuccess: () => toast.success("Profile picture updated"),
209	              onError: () => toast.error("Failed to update profile picture"),
210	            }
211	          );
212	        },
213	      }
214	    );
215	
216	    // Reset input so the same file can be re-selected
217	    event.target.value = "";
218	  }
219	
220	  function handleDelete() {
221	    updatePhoto(
222	      { photoFileId: null },
223	      {
224	        onSuccess: () => toast.success("Profile picture removed"),
225	        onError: () => toast.error("Failed to remove profile picture"),
226	      }
227	    );
228	  }
229	
230	  return (
231	    <SettingsCard>
232	      <CardHeader title="Profile Picture" />
233	
234	      <div className="new-design flex items-center justify-between gap-3 rounded-lg bg-[#EDE9E3] p-4 text-center">
235	        {/* Avatar */}
236	        <div className="h-9 w-9 shrink-0 overflow-hidden rounded-[4px]">
237	          <UserAvatar firstName={firstName} size={36} src={photoData?.url} />
238	        </div>
239	
240	        {/* Actions */}
241	        <div className="flex items-center gap-4">
242	          <button
243	            className="rounded-lg border border-[#A8A29E] bg-[#F5F3EF] px-3 py-1.5 font-medium font-new-sans text-[#44403C] text-sm transition-colors hover:bg-[#EDE9E3]"
244	            disabled={isPending}
245	            onClick={handleReplaceClick}
246	            type="button"
247	          >
248	            {isUploading ? "Uploading…" : "Replace Profile Image"}
249	          </button>
250	
251	          {photoFileId && (
252	            <button
253	              aria-label="Remove profile picture"
254	              className="transition-colors hover:text-[#44403C]"
255	              disabled={isPending}
256	              onClick={handleDelete}
257	              type="button"
258	            >
259	              <Trash2 className="h-5 w-5" />
260	            </button>
261	          )}
262	        </div>
263	      </div>
264	
265	      <input
266	        accept={IMAGE_ACCEPT_TYPES}
267	        className="hidden"
268	        onChange={handleFileChange}
269	        ref={fileInputRef}
270	        type="file"
271	      />
272	    </SettingsCard>
273	  );
274	}
