280	function NotificationsCard() {
281	  const { data: userSettings, isLoading } = useUserSettings();
282	  const updateMutation = useUpdateUserSettings();
283	  const debounceRef = useRef<NodeJS.Timeout | null>(null);
284	
285	  const notif = userSettings?.[UserSetting.Notifications] ?? null;
286	
287	  const handleToggle = useCallback(
288	    (field: keyof UserNotificationsSetting, value: boolean) => {
289	      if (!notif) return;
290	      if (debounceRef.current) clearTimeout(debounceRef.current);
291	      debounceRef.current = setTimeout(() => {
292	        updateMutation.mutate(
293	          { [UserSetting.Notifications]: { ...notif, [field]: value } },
294	          {
295	            onSuccess: () => toast.success("Settings updated"),
296	            onError: () => toast.error("Failed to update settings"),
297	          }
298	        );
299	      }, 300);
300	    },
301	    [notif, updateMutation]
302	  );
303	
304	  const items: {
305	    field: keyof UserNotificationsSetting;
306	    icon: ReactNode;
307	    title: string;
308	    description: string;
309	  }[] = [
310	    {
311	      field: "general",
312	      icon: <BellRing className="h-5 w-5 shrink-0 text-[#78716C]" />,
313	      title: "General Notification",
314	      description: "Enable all Notification for Updates and Alerts",
315	    },
316	    {
317	      field: "buyback",
318	      icon: <RefreshCw className="h-5 w-5 shrink-0 text-[#78716C]" />,
319	      title: "BuyBack Notifications",
320	      description: "Alerts for BuyBack Repayment, due dates etc",
321	    },
322	    {
323	      field: "accountSecurity",
324	      icon: <ShieldAlert className="h-5 w-5 shrink-0 text-[#78716C]" />,
325	      title: "Account Security Alerts",
326	      description: "Notifications for login attempts, password changes",
327	    },
328	  ];
329	
330	  return (
331	    <SettingsCard>
332	      <CardHeader title="Notification settings" />
333	
334	      <div className="flex flex-col divide-y divide-[#E7E5E4]">
335	        {isLoading
336	          ? [1, 2, 3].map((i) => (
337	              <div
338	                className="h-14 animate-pulse bg-[#F5F3EF] first:rounded-t-xl last:rounded-b-xl"
339	                key={i}
340	              />
341	            ))
342	          : items.map(({ field, icon, title, description }) => (
343	              <div
344	                className="flex items-center gap-4 py-3 first:pt-0 last:pb-0"
345	                key={field}
346	              >
347	                {icon}
348	                <div className="flex flex-1 flex-col leading-[150%] tracking-[-1%]">
349	                  <span className="font-medium font-new-sans text-sm">
350	                    {title}
351	                  </span>
352	                  <span className="font-new-sans text-sm">{description}</span>
353	                </div>
354	                <Switch
355	                  checked={notif?.[field] ?? false}
356	                  disabled={!notif}
357	                  onCheckedChange={(value) => handleToggle(field, value)}
358	                />
359	              </div>
360	            ))}
361	      </div>
362	    </SettingsCard>
363	  );
364	}
