1	import { getApi } from "@/shared/api/api";
2	import { API_ROUTES } from "@/shared/config/api-routes";
3	import { ENV } from "@/shared/config/env";
4	import type {
5	  Address,
6	  Profile,
7	  UpdateProfileDto,
8	  UpdateProfilePhotoDto,
9	  UpdateSettingsDto,
10	  UpsertAddressDto,
11	  UserSettings,
12	} from "../model/types";
13	
14	export async function getProfile(): Promise<Profile> {
15	  const api = await getApi({ auth: true });
16	
17	  const response = await api.get<Profile>(API_ROUTES.PROFILE.GET);
18	
19	  return response.data;
20	}
21	
22	export async function getProfileWithToken(
23	  accessToken: string,
24	): Promise<Profile> {
25	  const url = `${ENV.NEXT_PUBLIC_APP_API_URL}${API_ROUTES.PROFILE.GET}`;
26	  const response = await fetch(url, {
27	    headers: {
28	      Authorization: `Bearer ${accessToken}`,
29	    },
30	  });
31	
