80	export function useUpdateUserSettings() {
81	  const queryClient = useQueryClient();
82	
83	  return useMutation({
84	    mutationFn: (data: UpdateSettingsDto) =>
85	      profileService.updateUserSettings(data),
86	    onMutate: async (newSettings) => {
87	      const queryKey = ApiKeys.userSettings();
88	
89	      await queryClient.cancelQueries({ queryKey });
90	
91	      const previousSettings = queryClient.getQueryData<UserSettings>(queryKey);
92	
93	      queryClient.setQueryData<UserSettings>(queryKey, (old) => {
94	        if (!old) return old;
95	
96	        return {
97	          ...old,
98	          ...newSettings,
99	        };
100	      });
101	
102	      return { previousSettings };
103	    },
104	    onError: (_error, _variables, context) => {
105	      if (context?.previousSettings) {
106	        queryClient.setQueryData(
107	          ApiKeys.userSettings(),
108	          context.previousSettings,
109	        );
110	      }
111	    },
112	    onSettled: () => {
113	      queryClient.invalidateQueries({
114	        queryKey: [TagsEnum.USER_SETTINGS],
115	      });
116	    },
117	  });
